  const { limit, offset } = listUsersQuery.parse(req.query);
  const users = [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ].slice(offset, offset + limit);
  // NOTE: email removed — don't leak PII on an unauthenticated endpoint
  res.json(users);
